      if (!agent.skills) continue;
      actions.push({
        kind: "skill-dir",
        skill: skill.name,
        agent: agentId,
        target: resolveAgentSkillPath(agent, skill.name, home),
      });
    }
  }
  return actions;
}

function buildFileWriteReverts(
