          dir,
          realRoot,
          ["claude-code"],
          "/home/test",
          "/repo/test",
        ),
        /must point to a Markdown source file/,
      );
    } finally {
      await rm(dir, { recursive: true });
    }
  });

  it("throws when source file does not exist", async () => {
    const compile = await getAdapter();
    const dir = await makeTmpDir();
