      await rm(dir, { recursive: true });
    }
  });

  it("produces actions for multiple detected agents", async () => {
    const compile = await getAdapter();
    const dir = await makeTmpDir();
    try {
      await writeFile(path.join(dir, "my-agent.md"), "# Agent");
